-- Enrichment marathon batch: MarketMan, MarketMuse, Marketo Engage, Maropost, Marq, Marqii, Marqo, Mastodon

-- ── MarketMan ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$MarketMan is a cloud-based restaurant back-of-house platform for inventory management, purchasing, and recipe costing.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$199/month (Starter plan)$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, New York, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$MarketMan Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$MarketMan review 2026: restaurant inventory, purchasing, and recipe costing software. See pricing tiers, POS integrations, pros, cons and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$MarketMan is a cloud-based restaurant management platform focused on back-of-house operations: inventory management, purchasing and ordering, recipe costing, and food cost control. Founded in 2013 and headquartered in New York City, MarketMan is now part of the Meal Ticket portfolio of restaurant technology brands. The platform is built for independent restaurants, multi-location groups, and commissary or ghost-kitchen operations that need visibility into food costs, waste, and vendor pricing. Core functionality centers on digitizing the ordering-to-payment workflow: restaurants place purchase orders with suppliers through the platform, scan or upload invoices (with OCR-based invoice scanning to reduce manual entry), and reconcile received goods against orders to catch price discrepancies and short shipments. MarketMan tracks real-time inventory counts, calculates recipe and plate costs down to the ingredient level, and flags price changes from vendors so operators can react before margins erode. Reporting dashboards surface cost-of-goods-sold (COGS), variance, and waste data across single or multiple locations. MarketMan integrates with more than 40 third-party systems, including point-of-sale platforms such as Toast, Lightspeed, TouchBistro, Clover and NCR Aloha, as well as accounting tools like QuickBooks and Xero, allowing sales and cost data to flow together automatically. Pricing is subscription-based and tiered by restaurant size and feature depth: a Starter plan begins around $199 per month, with a Growth plan around $249 per month adding deeper reporting and COGS tools, and a custom-priced Enterprise plan for multi-unit or commissary operations; annual billing typically carries a discount versus month-to-month, and a one-time setup fee has historically applied to new accounts. MarketMan holds strong review scores on Capterra, GetApp, and Software Advice (around 4.7/5) and a slightly lower but still positive score on G2 (around 4.3/5), with users praising ease of use and cost visibility while citing setup complexity and cancellation friction as recurring criticisms. Its main competitors in the restaurant inventory and purchasing category include Restaurant365, xtraCHEF (Toast), Craftable, and Apicbase. MarketMan differentiates through its invoice-scanning accuracy, broad POS/accounting integration catalog, and focus specifically on inventory and purchasing rather than full back-office accounting, positioning it as a specialist tool that restaurants layer alongside a POS and payroll system rather than a replacement for either.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3';

