-- ── Marqii ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Marqii is a digital hospitality platform that automates restaurant menu updates, online listings, review management, and local marketing.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$74.99/month per location (Base plan)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$New York, New York, US$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Marqii Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Marqii review 2026: digital hospitality platform for menu updates, online listings, and review management. See pricing, features, pros, cons, and more.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Marqii is a digital hospitality and restaurant marketing platform founded in 2016 and headquartered in New York City. The company was formerly known as Bestof before rebranding to Marqii. Marqii has raised approximately 18.6 million dollars in venture funding to build out its platform, which focuses on automating the operational marketing tasks that independent and multi-location restaurants otherwise handle manually across dozens of third-party sites. The platform's core function is automated menu distribution: restaurants update their menu once inside Marqii, and the platform pushes that update out to online listing sites, delivery marketplaces, and review platforms so pricing, items, and hours stay consistent everywhere customers look for the business. Beyond menu syndication, Marqii offers online review management (aggregating and helping respond to reviews across platforms), local SEO and listings optimization to improve visibility in local search and maps results, and social media campaign management tools for restaurant marketing teams with limited in-house marketing resources. Marqii serves independent restaurants, multi-location restaurant brands, ghost kitchens and virtual brands, and marketing agencies that manage restaurant clients. Notably, Marqii has an integration partnership with MarketMan, another restaurant technology platform, reflecting a broader trend of restaurant tech vendors connecting front-of-house marketing and back-of-house operations data. Pricing is tiered per location: a Base plan starts around 74.99 dollars per month per location, a Pro plan is priced around 119.99 dollars per month per location, a Pro+Advanced tier runs around 149.99 dollars per month per location, and custom Enterprise pricing is available for larger multi-location groups. Marqii's competitors include restaurant marketing and reputation management platforms such as Popmenu, SinglePlatform, Yext (for broader local listings), and BentoBox, as well as review management tools like Podium. Marqii differentiates itself by focusing specifically on the restaurant and hospitality vertical, combining menu syndication, review management, and local SEO into a single subscription rather than requiring restaurants to piece together separate listings, review, and social tools.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fd376b9a-76da-4d57-99b7-dede36f6af47';

