-- ── Mastodon ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Mastodon is free, open-source software for running decentralized, federated social networks using the ActivityPub protocol.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); joining an existing server is free$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Berlin, Germany (nonprofit governance transitioning to a foundation model as of 2025)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Japanese$q$, $q$Portuguese$q$]::text[],
  seo_title = COALESCE($q$Mastodon Review 2026: Features, How It Works and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Mastodon review 2026: the open-source, decentralized social network. Learn how federation works, key features, pros, cons, and Twitter/X alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Mastodon is free, open-source software for running decentralized social networks, created by German software developer Eugen Rochko. Rochko began working on Mastodon in early 2016 while finishing his computer science degree at the University of Jena, motivated by dissatisfaction with Twitter's direction and, by his own account, concern over reports that investor Peter Thiel might acquire the platform. Mastodon was publicly released in October 2016 and funded in its early years through Patreon and OpenCollective crowdfunding, an open-source development grant from Samsung, and a small grant from the European Commission. Unlike centralized social networks such as Twitter/X or Facebook, Mastodon is built on the ActivityPub protocol and operates as a federated network: rather than one company running a single service, anyone can run their own Mastodon server (called an instance), each with its own moderation rules, community norms, and administrators, while users on different servers can still follow, reply to, and interact with each other across the network, similar to how email works across different providers. This decentralized structure, often referred to as the Fediverse, also includes other ActivityPub-compatible software such as Pixelfed (photos) and PeerTube (video), which can interoperate with Mastodon accounts. The organization behind the flagship codebase was originally incorporated in 2021 as Mastodon gGmbH, a German nonprofit LLC structure, though it lost formal non-profit tax status after Germany changed eligibility rules for software projects; in 2024 a separate US-based nonprofit, Mastodon, Inc., was incorporated as a 501(c)(3) to support the project's growth, and in 2025 the organization began transitioning governance toward a new foundation model with more community input. Mastodon experienced its largest growth spike in November 2022, gaining roughly 230,000 new members in the first week alone following Elon Musk's acquisition of Twitter, with monthly active users peaking around 2.6 million shortly after. By 2026, Mastodon's monthly active users had settled into a lower, more stable range of roughly 750,000 to 1 million (with some measurements showing figures below 700,000), against a much larger base of over 10.5 million total registered accounts across more than 10,000 active instances, reflecting the common pattern of federated networks retaining a large registered base but a smaller consistently active audience. Mastodon's software itself is free and open source under an AGPL license; there is no cost to join an existing public instance, and self-hosting a private or community instance is free of software licensing costs but requires paying for hosting infrastructure and moderation time. Mastodon's main alternatives and competitors in the decentralized and post-Twitter social space include Bluesky (built on the separate AT Protocol), Threads (Meta's centralized Twitter competitor with limited ActivityPub interoperability), and other Fediverse projects. Mastodon differentiates itself through its fully decentralized, non-corporate governance model, chronological (non-algorithmic) timelines by default, and community-run moderation, appealing to users seeking an alternative to advertising-driven, algorithmically curated centralized social platforms.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9fecdcd9-2620-4cdf-982f-3615b76750b1';

