INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Purchase order management$q$, $q$Create, send, and track purchase orders to suppliers directly from the platform, keeping ordering history centralized.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Invoice scanning$q$, $q$OCR-based invoice capture reduces manual data entry and flags price discrepancies against purchase orders on receipt.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Recipe and menu costing$q$, $q$Break recipes down to ingredient-level cost to calculate plate cost and monitor menu profitability as prices change.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Real-time inventory tracking$q$, $q$Track stock levels and usage across one or many locations to reduce waste and catch shrinkage.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$POS and accounting integrations$q$, $q$Connects with 40-plus POS and accounting platforms including Toast, Lightspeed, QuickBooks, and Xero.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Vendor price tracking$q$, $q$Alerts operators to vendor price changes so they can react before costs erode margins.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Multi-location and commissary reporting$q$, $q$Consolidated dashboards for multi-unit groups and commissary kitchens supplying multiple sites.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$COGS and variance reporting$q$, $q$Reporting tools calculate cost-of-goods-sold and variance to highlight waste and over-ordering.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Strong ease-of-use ratings across major review platforms$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Deep POS and accounting integration catalog$q$, 1);
