INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Initial setup and menu/recipe data entry can be time-consuming$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Some users report friction when canceling or downgrading plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Pricing sits higher than basic spreadsheet or lightweight inventory apps$q$, 2);
