INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Advanced features are gated behind higher-priced tiers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$What is MarketMan used for?$q$, $q$MarketMan is used by restaurants to manage inventory, purchasing, invoice reconciliation, and recipe costing so operators can control food cost and reduce waste.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$How much does MarketMan cost?$q$, $q$Plans start around $199 per month for the Starter tier, with a Growth plan around $249 per month; larger operations use a custom-quoted Enterprise plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Does MarketMan integrate with my POS system?$q$, $q$MarketMan integrates with more than 40 POS and accounting platforms, including Toast, Lightspeed, TouchBistro, Clover, NCR Aloha, QuickBooks, and Xero.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Is MarketMan suitable for multi-location restaurant groups?$q$, $q$Yes, MarketMan offers multi-unit and commissary kitchen inventory features with consolidated reporting across locations.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Who owns MarketMan?$q$, $q$MarketMan operates as part of the Meal Ticket portfolio of restaurant technology brands.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Does MarketMan offer a free trial?$q$, $q$MarketMan typically offers demos and trial access; prospective customers should check the current offer on marketman.com.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Independent restaurant cost control$q$, $q$A single-location restaurant uses MarketMan to track ingredient costs, catch vendor price increases, and keep food cost percentage on target.$q$, $q$Independent restaurant owners and chefs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Multi-unit chain purchasing$q$, $q$A regional restaurant group standardizes purchasing and inventory counts across locations with consolidated cost reporting.$q$, $q$Multi-location restaurant operators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Commissary and ghost kitchen inventory$q$, $q$A commissary kitchen supplying multiple virtual brands uses MarketMan to manage shared inventory and allocate costs accurately.$q$, $q$Commissary and ghost kitchen operators$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Starter$q$, $q$$199/month$q$, $q$monthly (annual discount available)$q$, NULL, $q$["Core inventory tracking","Purchase order management","Basic reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Growth$q$, $q$$249/month$q$, $q$monthly (annual discount available)$q$, NULL, $q$["Advanced reporting","COGS tools","Invoice scanning"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$Enterprise$q$, $q$Custom quote$q$, $q$annual contract$q$, NULL, $q$["Multi-location and commissary support","Dedicated account management","Advanced integrations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MarketMan is restaurant back-of-house software that helps operators manage inventory, purchasing, and recipe costs from a single cloud platform. It was built to replace spreadsheet-based ordering and manual invoice reconciliation with a system that tracks stock levels, vendor pricing, and food cost in real time.$q$, $q$The platform is aimed at independent restaurants, multi-location chains, and commissary or ghost-kitchen operations that need to control food cost as a percentage of revenue. It connects purchasing, receiving, and inventory counts to recipe-level costing so operators can see exactly how ingredient price changes affect menu profitability.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MarketMan's core workflow covers purchase order creation, invoice scanning and receiving, and inventory counts, all reconciled against expected costs to flag discrepancies. Recipe and menu costing tools break dishes down to ingredient-level cost so operators can price menus accurately and spot margin erosion early.$q$, $q$The platform integrates with over 40 POS and accounting systems, including Toast, Lightspeed, TouchBistro, Clover, NCR Aloha, QuickBooks, and Xero, so sales and cost data stay synchronized without manual re-entry. Multi-location reporting and dashboards give regional or corporate teams a consolidated view of cost trends and vendor pricing across every unit.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e9de17dd-4f9b-4e9c-970b-67a6e9b13dd3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MarketMan uses tiered subscription pricing based on restaurant size and feature needs, starting with a Starter plan around $199 per month and a Growth plan around $249 per month that adds deeper reporting and COGS tools. Larger or multi-unit operations typically move to a custom-quoted Enterprise plan.$q$, $q$Annual billing is discounted relative to month-to-month pricing, and new accounts have historically been subject to a one-time setup fee. Exact pricing can vary by negotiated terms, so restaurants should confirm current numbers directly with MarketMan sales.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$AI topic modeling$q$, $q$Analyzes top-ranking content for a subject to build a data-driven map of related topics, entities, and questions.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Content optimization scoring$q$, $q$Scores drafts in real time against the topic model to guide writers toward comprehensive coverage.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Content briefs$q$, $q$Generates structured, topic-based briefs that can be handed to writers or freelancers.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Content inventory and auditing$q$, $q$Audits existing site content for topical quality and prioritizes pages for improvement.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Competitive content analysis$q$, $q$Compares site-wide topical coverage against competitor domains to find content gaps.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Content strategy planning$q$, $q$Helps teams prioritize content investments based on ranking difficulty and topical authority.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Question and entity research$q$, $q$Surfaces the specific questions and named entities top-ranking pages address for a topic.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Deep, data-driven topic modeling beyond basic keyword tools$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Useful for planning and briefing, not just post-publish scoring$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Content inventory helps prioritize which existing pages to update$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Established, long-running product with a mature methodology$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Now backed by Siteimprove's broader digital governance platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Pricing is no longer transparent and requires a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Learning curve for teams new to topic modeling concepts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Can feel expensive for very small teams or solo bloggers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Some features overlap with cheaper optimization-only tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Acquisition by Siteimprove creates uncertainty around standalone roadmap$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$What does MarketMuse do?$q$, $q$MarketMuse uses AI to analyze topical coverage of top-ranking content, then helps teams plan, brief, and optimize content to be more comprehensive and competitive for search.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Is MarketMuse free?$q$, $q$MarketMuse has offered a limited free plan, with paid plans required for full topic modeling, content briefs, and inventory features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Who owns MarketMuse now?$q$, $q$MarketMuse was acquired by Siteimprove in late 2024 and now operates as part of Siteimprove's content and digital governance offerings.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Who founded MarketMuse?$q$, $q$MarketMuse was founded in 2013 by Aki Balogh and Jeff Coyle.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$How is MarketMuse different from Surfer SEO or Clearscope?$q$, $q$MarketMuse emphasizes deep topic modeling and content strategy planning, while tools like Surfer SEO and Clearscope focus more narrowly on on-page optimization scoring.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$What is MarketMuse's pricing model today?$q$, $q$MarketMuse has moved toward custom, quote-based pricing since being acquired by Siteimprove, rather than fully public self-serve tiers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$SEO content strategy planning$q$, $q$An SEO team uses MarketMuse to identify topical gaps and prioritize new content based on competitive difficulty and topical authority.$q$, $q$In-house SEO and content marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Content brief creation for freelance writers$q$, $q$A content agency generates data-backed briefs in MarketMuse to hand off consistent, comprehensive assignments to freelance writers.$q$, $q$Content marketing agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Existing content audits$q$, $q$A publisher audits its content inventory in MarketMuse to find underperforming pages worth updating for topical completeness.$q$, $q$Publishers and enterprise content teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["Limited monthly content queries","No content inventory"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Optimize$q$, $q$From approximately $99/month (historical, now quote-based)$q$, $q$monthly or annual$q$, NULL, $q$["Real-time content scoring","Topic modeling for individual pages"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$Research / Strategy$q$, $q$Custom quote$q$, $q$annual contract$q$, NULL, $q$["Content inventory and auditing","Competitive research","Site-wide strategy planning"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MarketMuse is an AI content research and strategy platform that analyzes topical coverage across the web to help content and SEO teams decide what to write, how comprehensive it needs to be, and where existing content falls short. It launched in 2013 and built its reputation on topic modeling technology that goes beyond simple keyword matching.$q$, $q$In late 2024 MarketMuse was acquired by Siteimprove, a website governance and digital experience platform, which now offers MarketMuse's content intelligence capabilities as part of a broader suite alongside accessibility and quality assurance tooling.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MarketMuse's flagship capability is topic modeling: it scans large sets of top-ranking pages for a subject and builds a map of related topics, questions, and entities that comprehensive content should cover, then scores drafts against that model in real time through its Optimize tool.$q$, $q$Additional modules cover content inventory auditing (scoring and prioritizing existing pages by topical authority and quality), competitive research (comparing site-wide topical coverage against competitors), and content brief generation, which turns topic models into structured writing briefs for writers or freelancers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b77c4b21-5cd3-47b0-a144-34c9f0369acb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MarketMuse has historically offered a free plan with limited monthly queries alongside paid Optimize, Research, and Strategy tiers, with entry paid pricing around $99 per month scaling up based on tracked topics, users, and content brief volume.$q$, $q$Following its acquisition by Siteimprove, MarketMuse has shifted toward custom, sales-assisted pricing rather than fully public self-serve rates, so prospective buyers should expect a sales conversation to get current numbers, especially for enterprise or bundled Siteimprove plans.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Smart campaigns and nurture programs$q$, $q$Automated, behavior-triggered email and multi-channel campaigns that nurture leads through the funnel.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Lead scoring and lifecycle management$q$, $q$Scores leads on fit and engagement to determine when they are sales-ready.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Account-based marketing (ABM)$q$, $q$Tools to identify, target, and personalize engagement for specific target accounts and buying committees.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Revenue attribution and analytics$q$, $q$Multi-touch attribution reporting connecting marketing activity to pipeline and revenue outcomes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$CRM integration$q$, $q$Native, deep integration with Salesforce and Microsoft Dynamics to sync leads, contacts, and campaign data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Dynamic content and personalization$q$, $q$Real-time web and email personalization based on visitor behavior and firmographic data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Landing pages and forms$q$, $q$Drag-and-drop builders for landing pages, forms, and email templates without developer support.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Adobe Experience Cloud integration$q$, $q$Connects with Adobe Analytics, Adobe Experience Manager, and Real-Time CDP for a unified customer data and content stack.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Deep, mature Salesforce and Microsoft Dynamics integration$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Powerful for complex, multi-touch B2B lead lifecycle management$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Strong revenue attribution and reporting capabilities$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Backed by Adobe's broader Experience Cloud ecosystem$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Extensive partner and agency ecosystem for implementation support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Pricing is opaque and requires a sales conversation, with high total cost of ownership$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Steep learning curve and complex administration compared to SMB tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Best suited to large marketing teams with dedicated marketing operations staff$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Add-ons for predictive scoring and enrichment increase cost significantly$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Smaller businesses often find HubSpot or similar tools more accessible$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$What is Marketo Engage used for?$q$, $q$Marketo Engage is used by B2B marketing teams for lead management, email marketing automation, account-based marketing, and revenue attribution reporting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Who owns Marketo Engage?$q$, $q$Marketo Engage is owned by Adobe, which acquired Marketo, Inc. in September 2018 for approximately 4.75 billion dollars.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$How much does Marketo Engage cost?$q$, $q$Adobe does not publish self-serve pricing; costs are quote-based and typically range from roughly 1,500 to 6,000 dollars or more per month depending on database size and modules.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Is Marketo Engage the same as Marketo?$q$, $q$Yes, Marketo Engage is the current product name for the marketing automation platform originally built by Marketo, Inc., now part of Adobe Experience Cloud.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$How is Marketo Engage different from HubSpot?$q$, $q$Marketo Engage is generally aimed at larger enterprise B2B organizations with complex lead lifecycles, while HubSpot is more commonly used by small and mid-sized businesses seeking an easier setup.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Does Marketo Engage integrate with Salesforce?$q$, $q$Yes, Marketo Engage has a long-standing, deep native integration with Salesforce for syncing leads, contacts, and campaign performance data.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Enterprise B2B lead nurturing$q$, $q$A large B2B software company uses Marketo Engage to run multi-touch nurture campaigns that move leads through a complex sales funnel.$q$, $q$Enterprise B2B marketing operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Account-based marketing programs$q$, $q$A marketing team targets a defined list of high-value accounts with personalized content and coordinated outreach across channels.$q$, $q$ABM and demand generation teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Marketing revenue attribution$q$, $q$A CMO uses Marketo Engage's attribution reporting to show which campaigns and channels are driving pipeline and closed revenue.$q$, $q$Marketing leadership and revenue operations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Select / Prime / Ultimate (naming varies by contract)$q$, $q$Custom quote$q$, $q$annual contract$q$, NULL, $q$["Email marketing and campaign automation","Lead scoring and nurturing","CRM integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$Enterprise add-ons$q$, $q$Custom quote$q$, $q$annual contract$q$, NULL, $q$["Account-based marketing","Predictive content and scoring","Advanced revenue attribution"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Marketo Engage is a B2B marketing automation platform originally built by Marketo, Inc. and acquired by Adobe in 2018 for approximately 4.75 billion dollars. It now operates as part of Adobe Experience Cloud, providing lead management, email marketing, and revenue attribution for mid-market and enterprise marketing teams.$q$, $q$The platform is designed around complex, multi-touch B2B buyer journeys, with deep CRM integration (particularly Salesforce), lead scoring, and account-based marketing tools that help align sales and marketing around shared pipeline goals.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Marketo Engage's engagement engine runs automated smart campaigns and nurture programs based on lead behavior and lifecycle stage, while its lead scoring model qualifies leads for handoff to sales based on fit and engagement signals.$q$, $q$Account-based marketing tools let teams target and personalize content for specific buying committees, and revenue attribution reporting connects marketing touchpoints to pipeline and closed revenue. Recent updates add AI-driven content suggestions and integration with Adobe's real-time Customer Data Platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd78a231-31fa-4eb1-8802-93fe59f582da', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Adobe does not publish simple self-serve pricing for Marketo Engage; costs are determined by database size, email volume, selected modules, and add-ons like predictive scoring or expanded API capacity, requiring a sales conversation to get a quote.$q$, $q$Typical mid-market to enterprise spend runs roughly 1,500 to 6,000 dollars or more per month, with large enterprise deployments and additional Adobe Experience Cloud products increasing total cost further.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Cross-channel marketing automation$q$, $q$Build customer journeys spanning email, SMS, and Meta ads from a single automation builder.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Audience segmentation$q$, $q$Segment contacts using behavioral and transactional data to personalize campaign targeting.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Ecommerce commerce cloud$q$, $q$Storefront and retail operations tools strengthened by the Retail Express acquisition in Australia.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$AI-driven merchandising$q$, $q$Merchandising Cloud applies AI to product recommendations and cross-sell placement.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Cart abandonment recovery$q$, $q$Automated cart recovery emails aimed at recapturing lost ecommerce revenue.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Unlimited contacts on select plans$q$, $q$The eCommerce plan includes unlimited contacts for growing online stores.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Custom contact fields$q$, $q$Store additional customer attributes to power segmentation and personalization.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Combines marketing automation and commerce operations under one vendor$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Meta ad integration alongside email and SMS in one journey builder$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Retail Express acquisition strengthens ecommerce and POS capabilities$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Tiered pricing scales from smaller stores to enterprise contact volumes$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Serves a large base of global brands across retail and other industries$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Enterprise-tier pricing is a significant jump from mid-tier plans$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Less name recognition in North America than competitors like Klaviyo or HubSpot$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Full commerce plus marketing stack may be more than smaller merchants need$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Pricing structure by contact volume can get expensive as lists grow$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Combining multiple clouds (Marketing, Commerce, Merchandising) adds setup complexity$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$What is Maropost used for?$q$, $q$Maropost is used for marketing automation across email, SMS, and social ads, as well as ecommerce commerce operations and AI-driven merchandising.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Who founded Maropost?$q$, $q$Maropost was founded in 2011 by CEO Ross Andrew Paquette and is headquartered in Toronto, Canada.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$How much does Maropost cost?$q$, $q$Maropost's Marketing Cloud starts around 251 dollars per month for the Essential plan, while a lower-cost eCommerce plan starts around 79.95 dollars per month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Does Maropost include ecommerce features?$q$, $q$Yes, Maropost's Commerce Cloud provides ecommerce and retail operations tools, strengthened by its acquisition of Australian retailer software company Retail Express.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$What are Maropost's main competitors?$q$, $q$Maropost competes with platforms like Klaviyo, Mailchimp, HubSpot, and Salesforce Marketing Cloud, as well as ecommerce platforms for the commerce side of its stack.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Is Maropost suitable for small businesses?$q$, $q$Maropost's eCommerce plan is priced for smaller online stores, but its full Marketing and Commerce Cloud suite is generally better suited to mid-market and enterprise retailers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Multichannel retail marketing$q$, $q$A retail brand runs coordinated email, SMS, and Meta ad campaigns from Maropost Marketing Cloud to drive repeat purchases.$q$, $q$Ecommerce and retail marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Unified commerce and marketing operations$q$, $q$A direct-to-consumer brand connects Commerce Cloud and Marketing Cloud so campaign targeting is powered by live purchase data.$q$, $q$Mid-market and enterprise ecommerce brands$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Cart abandonment recovery$q$, $q$A smaller online store uses the eCommerce plan to automate cart recovery emails and recapture lost sales.$q$, $q$Small to mid-sized online store owners$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$eCommerce$q$, $q$$79.95/month$q$, $q$monthly$q$, NULL, $q$["Unlimited contacts","Cart abandonment recovery emails","Basic email marketing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Essential$q$, $q$$251/month$q$, $q$monthly or annual$q$, NULL, $q$["Up to 250,000 contacts","5 automated journeys","5 users","50 custom contact fields"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Professional$q$, $q$$764/month$q$, $q$monthly or annual$q$, NULL, $q$["Up to 1 million contacts","More automated journeys","Expanded feature set"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$Enterprise$q$, $q$$18,349/year$q$, $q$annual$q$, NULL, $q$["Unlimited usage","Dedicated support","Custom integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Maropost is a Toronto-based marketing automation and commerce platform founded in 2011 by Ross Andrew Paquette. It combines a Marketing Cloud for email, SMS, and social ad campaigns with a Commerce Cloud for ecommerce operations and a Merchandising Cloud for AI-driven product recommendations.$q$, $q$The platform is built for retailers and direct-to-consumer brands that want marketing and commerce data connected under one vendor, rather than integrating separate email marketing and ecommerce platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Maropost Marketing Cloud supports segmentation, cross-channel customer journeys, and automated campaigns across email, SMS, and Meta ads, giving marketers a single interface to plan and launch personalized communications.$q$, $q$Maropost Commerce Cloud, strengthened by the acquisition of Australian retail software provider Retail Express, adds ecommerce storefront and point-of-sale capabilities, while the Merchandising Cloud applies AI to product recommendations and cross-sell decisions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1ae57dc6-eaf6-4dcb-af35-03f42db55697', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Maropost's Marketing Cloud pricing is tiered by contact volume, starting with an Essential plan around 251 dollars per month for roughly 250,000 contacts, scaling to a Professional plan around 764 dollars per month for larger lists, and an Enterprise tier priced around 18,349 dollars per year for unlimited usage.$q$, $q$A separate, lower-cost eCommerce plan starts around 79.95 dollars per month, aimed at smaller online stores that primarily need email marketing features like cart recovery rather than the full multichannel Marketing Cloud.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Template locking and smart fields$q$, $q$Lock brand elements like logos and colors while allowing safe editing of variable content within templates.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Brand asset library$q$, $q$Centralized storage for approved logos, images, and brand guidelines accessible to all template users.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$DAM and CRM integrations$q$, $q$Connects with Aprimo, Bynder, Salesforce, and HubSpot to fit into broader marketing operations stacks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Web publishing$q$, $q$Publish designs directly as responsive web pages or shareable links without exporting to another tool.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$InDesign import$q$, $q$Import existing Adobe InDesign files to convert legacy brand assets into Marq templates.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Approval workflows$q$, $q$Enterprise-tier workflows route personalized content through approval before publication or print.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Print and digital output$q$, $q$Design once and export or order print materials alongside digital and web formats.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Strong template locking makes it easy to keep distributed teams on-brand$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Free plan available for individuals or very light use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Integrates with common DAM and CRM tools used by marketing operations$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Well suited to franchises and multi-location businesses needing local personalization$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Web publishing lets users skip export steps for simple digital pages$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Less suited to freeform, general-purpose graphic design than tools like Canva$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Business/Enterprise pricing is custom and not published$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Per-user Team pricing can add up for larger organizations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Smaller template and stock asset library compared to larger design platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Brand and admin setup requires upfront time investment to configure correctly$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Is Marq the same company as Lucidpress?$q$, $q$Yes, Marq is the same company and product as Lucidpress, which rebranded to Marq in 2021 to reflect its focus on brand templating.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$How much does Marq cost?$q$, $q$Marq has a free plan, a Pro plan from around 10 dollars per month, a Team plan around 12 dollars per user per month, and a custom-priced Business or Enterprise tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$What is Marq used for?$q$, $q$Marq is used to create locked, on-brand templates that non-designers across an organization can safely personalize for marketing materials.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Does Marq integrate with other marketing tools?$q$, $q$Yes, Marq integrates with digital asset management platforms like Aprimo and Bynder, and CRM tools such as Salesforce and HubSpot.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Is Marq good for franchises or multi-location businesses?$q$, $q$Yes, Marq's template locking and personalization features are commonly used by franchises, real estate brokerages, and multi-location retailers to keep local marketing on-brand.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$How is Marq different from Canva?$q$, $q$Marq focuses on locked, brand-controlled templates for distributed teams, while Canva is more of a general-purpose design tool with broader creative freedom.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Franchise marketing localization$q$, $q$A franchise brand builds locked templates in Marq so individual franchisees can personalize local promotions without breaking brand guidelines.$q$, $q$Franchise and multi-location marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Sales collateral personalization$q$, $q$A sales team personalizes approved one-pagers and proposals with client-specific details while keeping brand design intact.$q$, $q$Sales enablement and marketing operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Distributed team brand consistency$q$, $q$A large organization with regional offices uses Marq's brand asset library and templates to standardize marketing output company-wide.$q$, $q$Brand and creative operations managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Limited templates","Basic design tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Pro$q$, $q$$10/month$q$, $q$monthly (annual discount available)$q$, NULL, $q$["2GB storage","Unlimited projects","Premium templates and stock photos","Web publishing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Team$q$, $q$$12/month per user$q$, $q$monthly (annual discount available)$q$, NULL, $q$["Content locking","Brand asset library","InDesign import","Group management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$Business / Enterprise$q$, $q$Custom quote$q$, $q$annual contract$q$, NULL, $q$["Approval workflows","Enterprise integrations","Advanced admin controls"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Marq, known as Lucidpress until its 2021 rebrand, is a cloud-based brand templating platform headquartered in Draper, Utah. It was founded in 2013 as an online publishing tool and evolved into a brand-enablement platform focused on scaling on-brand content production across distributed teams.$q$, $q$The platform's core idea is template locking: design or brand teams build controlled templates that non-designers across the organization can safely personalize, protecting brand consistency while removing the design bottleneck for routine marketing materials.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Marq's smart fields and content locking let administrators decide exactly which parts of a template, such as text, images, or data fields, other users can edit, keeping logos, colors, and layout locked to brand guidelines.$q$, $q$The platform integrates with digital asset management tools like Aprimo and Bynder and CRM systems such as Salesforce and HubSpot, and supports InDesign file import on higher tiers, making it easier to migrate existing brand assets into managed templates.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d954194-528b-4c02-af62-5032ccb9918a', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Marq offers a free plan with limited features, a Pro plan starting around 10 dollars per month for individuals needing unlimited projects and premium assets, and a Team plan around 12 dollars per user per month adding content locking and brand asset management.$q$, $q$A custom-priced Business or Enterprise tier is available for larger organizations that need approval workflows, enterprise integrations, and advanced admin controls, with annual billing offering a discount over monthly pricing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Automated menu syndication$q$, $q$Update a menu once and push changes automatically across connected online listings, delivery, and review sites.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Online review management$q$, $q$Aggregate reviews from multiple platforms and manage responses from a single dashboard.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Local SEO and listings optimization$q$, $q$Improve visibility and accuracy in local search and maps results across directories.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Social media campaign management$q$, $q$Plan and manage social content and campaigns for restaurant marketing teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Multi-location dashboard$q$, $q$Manage menus, listings, and reviews across multiple restaurant locations from one account.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$MarketMan integration$q$, $q$Connects with MarketMan's back-of-house inventory platform through an announced partnership.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Automates a genuinely time-consuming manual task (multi-site menu updates)$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Combines menu syndication, reviews, and local SEO in one subscription$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Purpose-built for the restaurant and hospitality vertical$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Supports independent restaurants through multi-location groups and agencies$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Partnership integrations with other restaurant tech platforms like MarketMan$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Per-location pricing can add up quickly for larger restaurant groups$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Higher-tier features require moving up to Pro or Pro+Advanced plans$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Primarily useful to restaurants with menu-driven, listings-heavy marketing needs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Enterprise pricing is not publicly listed and requires a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Smaller company scale compared to broader local-listings platforms like Yext$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$What is Marqii used for?$q$, $q$Marqii is used by restaurants to automate menu updates across online listing sites, manage online reviews, and improve local search visibility.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$How much does Marqii cost?$q$, $q$Marqii prices per location, starting around 74.99 dollars per month for the Base plan, with Pro and Pro+Advanced tiers priced higher, plus custom Enterprise pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Was Marqii previously known by another name?$q$, $q$Yes, Marqii was formerly known as Bestof before rebranding.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Does Marqii integrate with restaurant inventory software?$q$, $q$Marqii has an announced integration partnership with MarketMan, a restaurant back-of-house inventory and purchasing platform.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Who uses Marqii?$q$, $q$Marqii serves independent restaurants, multi-location restaurant brands, ghost kitchens, virtual brands, and marketing agencies managing restaurant clients.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$How much funding has Marqii raised?$q$, $q$Marqii has raised approximately 18.6 million dollars in venture funding.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Multi-site menu consistency$q$, $q$A restaurant updates its menu once in Marqii and the change automatically syncs across delivery apps, listings, and its website.$q$, $q$Independent restaurants and multi-location brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Reputation management$q$, $q$A restaurant marketing manager monitors and responds to reviews across platforms from a single Marqii dashboard.$q$, $q$Restaurant marketing and hospitality teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Agency management of restaurant clients$q$, $q$A marketing agency uses Marqii to manage menus, listings, and reviews across many restaurant clients from one account.$q$, $q$Restaurant marketing agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Base$q$, $q$$74.99/month per location$q$, $q$monthly$q$, NULL, $q$["Menu syndication","Basic listings management"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Pro$q$, $q$$119.99/month per location$q$, $q$monthly$q$, NULL, $q$["Review management","Expanded listings coverage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Pro+Advanced$q$, $q$$149.99/month per location$q$, $q$monthly$q$, NULL, $q$["Local SEO optimization","Social media campaign management"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$Enterprise$q$, $q$Custom quote$q$, $q$annual contract$q$, NULL, $q$["Multi-location management","Dedicated support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Marqii is a digital hospitality platform, founded in 2016 and headquartered in New York City, that helps restaurants automate menu updates, manage online reviews, and improve local search visibility. The company was formerly known as Bestof before rebranding to Marqii.$q$, $q$The platform is built specifically for restaurants, ghost kitchens, and hospitality brands that need to keep menu and business information consistent across dozens of online listing, delivery, and review sites without manual per-site updates.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Marqii's core feature is automated menu syndication: a single menu update in Marqii propagates across connected listing sites, delivery marketplaces, and review platforms, reducing the manual work of keeping pricing and items accurate everywhere.$q$, $q$The platform also provides review aggregation and response management, local SEO and listings optimization, and social media campaign management, and integrates with restaurant operations platforms including MarketMan through an announced partnership.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd376b9a-76da-4d57-99b7-dede36f6af47', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Marqii prices per restaurant location, with a Base plan starting around 74.99 dollars per month per location, a Pro plan around 119.99 dollars per month per location, and a Pro+Advanced tier around 149.99 dollars per month per location.$q$, $q$Larger multi-location restaurant groups and enterprise accounts can access custom pricing, typically negotiated based on the number of locations and feature requirements.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Multimodal semantic search$q$, $q$Search across text and images using embedding-based similarity rather than exact keyword matching.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Bundled embedding generation$q$, $q$Generates vector embeddings inside the engine using models like CLIP and Sentence Transformers, no separate embedding pipeline required.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Tensor, lexical, and hybrid search$q$, $q$Supports multiple search modes combining vector similarity with traditional keyword search.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Single REST API$q$, $q$One API handles indexing, embedding generation, and retrieval, simplifying integration for developers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Flexible deployment$q$, $q$Runs locally with Docker, on Kubernetes, or as the managed Marqo Cloud service on AWS.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Ecommerce-tuned embedding models$q$, $q$Specialized models trained for categories like fashion, beauty, electronics, and home goods product discovery.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Open-source core$q$, $q$Core engine code is open source and free to self-host and customize.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Bundles embedding generation with storage and retrieval, simplifying architecture$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Open-source core is free for self-managed deployments$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Supports multimodal (text and image) search out of the box$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Backed by venture funding including a Series A led by Lightspeed$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Increasing focus on ecommerce-specific embedding models improves relevance for retail search$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Narrowing focus toward ecommerce search may limit fit for other use-cases$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Marqo Cloud's original general vector-database offering is being deprioritized$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Self-hosting requires infrastructure and DevOps expertise$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Smaller company and community compared to larger vector database vendors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Managed cloud pricing is usage-based and not fully transparent upfront$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$What is Marqo used for?$q$, $q$Marqo is used to build semantic and multimodal search, letting applications search text and images by meaning rather than exact keyword matches, with growing focus on ecommerce product discovery.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Is Marqo open source?$q$, $q$Yes, Marqo's core engine is open source and free to self-host, with a managed Marqo Cloud option also available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Who founded Marqo?$q$, $q$Marqo was founded in 2022 in Melbourne, Australia, by Jesse Clark and Tom Hamer, both former Amazon engineers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$How much funding has Marqo raised?$q$, $q$Marqo has raised approximately 17.8 million dollars across pre-seed, seed, and a 12.5 million dollar Series A round led by Lightspeed Venture Partners.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$What technology is Marqo built on?$q$, $q$Marqo is built on Vespa for storage and retrieval and FastAPI for its HTTP interface, with bundled model inference using Sentence Transformers, OpenCLIP, and ONNX.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Is Marqo the same as Marq or Marqii?$q$, $q$No, Marqo is an unrelated AI vector search company; Marq is a design and brand templating platform, and Marqii is a restaurant marketing platform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Ecommerce product discovery$q$, $q$An online retailer uses Marqo's ecommerce-tuned embedding models to power visual and semantic product search on their storefront.$q$, $q$Ecommerce engineering and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Multimodal application search$q$, $q$A developer builds an application that searches both text descriptions and images using Marqo's single API and bundled embeddings.$q$, $q$AI application developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Self-hosted semantic search infrastructure$q$, $q$An engineering team self-hosts Marqo's open-source core on Kubernetes to maintain full control over their search infrastructure.$q$, $q$Infrastructure and machine learning engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Open Source$q$, $q$Free$q$, $q$n/a (self-hosted)$q$, NULL, $q$["Full core engine access","Self-managed deployment via Docker or Kubernetes"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Marqo Cloud$q$, $q$Usage-based$q$, $q$monthly$q$, NULL, $q$["Managed hosting on AWS","Production-grade infrastructure"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$Enterprise$q$, $q$Custom quote$q$, $q$annual contract$q$, NULL, $q$["Advanced security","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Marqo is an open-source vector search engine founded in 2022 in Melbourne, Australia, by former Amazon engineers Jesse Clark and Tom Hamer. It bundles embedding generation, vector storage, and retrieval into a single system accessible via one REST API, aimed at developers building semantic and multimodal search into applications.$q$, $q$The company has raised approximately 17.8 million dollars across pre-seed, seed, and Series A rounds, with the Series A led by Lightspeed Venture Partners. Marqo has increasingly focused its positioning on AI-native ecommerce search rather than general-purpose vector database infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Marqo supports tensor, lexical, and hybrid search across text and images through a single API, using models like CLIP for images and sentence-transformer models for text, with model inference bundled directly into the engine.$q$, $q$Built on Vespa for storage and retrieval and FastAPI for its HTTP layer, Marqo can be deployed locally with Docker, on Kubernetes, or consumed as the managed Marqo Cloud service on AWS, and increasingly ships specialized embedding models tuned for ecommerce categories like fashion and electronics.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Marqo's open-source core is free to self-host and manage, making it accessible to developers comfortable running their own infrastructure. Marqo Cloud offers a managed, usage-based option for teams that want production-grade hosting without operating the underlying infrastructure themselves.$q$, $q$Enterprise plans add advanced security and dedicated support, with pricing determined based on usage volume and support requirements rather than fixed public tiers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7bc828a9-6a44-47e7-9d64-c584650ed6e0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Federated instances (ActivityPub)$q$, $q$Anyone can run a Mastodon server that interoperates with other servers across the Fediverse via the open ActivityPub protocol.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Chronological timelines$q$, $q$Timelines are chronological by default rather than algorithmically ranked, unlike most centralized social platforms.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Community-based moderation$q$, $q$Each instance sets its own rules and moderation policy, allowing communities tailored to specific interests or values.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Content warnings and granular privacy$q$, $q$Posts can be tagged with content warnings and set to different visibility levels, from public to followers-only.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Cross-app interoperability$q$, $q$Interacts with other ActivityPub-based Fediverse apps like Pixelfed for photos and PeerTube for video.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Open-source, self-hostable$q$, $q$The full codebase is open source, letting individuals and organizations self-host their own branded instance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$No advertising-driven algorithm$q$, $q$The core platform does not rely on an advertising-optimized recommendation algorithm to drive engagement.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Fully open source with no licensing cost for the software itself$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Decentralized governance avoids single-company control of the network$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Community-specific moderation allows tailored, values-aligned instances$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Chronological timeline avoids algorithmic engagement manipulation$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Interoperates with a broader ecosystem of Fediverse apps$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Fragmented experience across instances can be confusing for new users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Discovery and content reach are weaker than algorithmically-optimized platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Self-hosting requires technical skill and ongoing infrastructure cost$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Monthly active users are far smaller than mainstream competitors like X or Threads$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Instance-hopping and moderation inconsistency can create a less unified experience$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$What is Mastodon?$q$, $q$Mastodon is free, open-source software for running decentralized, federated social networks, created by Eugen Rochko and released in October 2016.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Is Mastodon free to use?$q$, $q$Yes, Mastodon is free and open source; joining most public instances costs nothing, though self-hosting a private instance requires paying for infrastructure.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$How does Mastodon differ from Twitter/X?$q$, $q$Mastodon is decentralized, with independent servers called instances that interoperate via the ActivityPub protocol, rather than being run by a single company, and it uses chronological rather than algorithmic timelines.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Who created Mastodon?$q$, $q$Mastodon was created by German software developer Eugen Rochko, who began building it in 2016 and publicly released it in October of that year.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$How many people use Mastodon?$q$, $q$Mastodon has over 10.5 million registered accounts, though monthly active users are considerably smaller, estimated at roughly 750,000 to 1 million as of 2026.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$What is the Fediverse?$q$, $q$The Fediverse is the broader network of interoperable, ActivityPub-based platforms that includes Mastodon along with apps like Pixelfed and PeerTube.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Decentralized public social networking$q$, $q$An individual joins a Mastodon instance aligned with their interests to post and follow others across the federated network.$q$, $q$Individuals seeking an alternative to centralized social platforms$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Community or organizational instance hosting$q$, $q$An organization or interest group self-hosts its own Mastodon instance to create a moderated community space under its own rules.$q$, $q$Communities, nonprofits, and organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Brand or public figure presence in the Fediverse$q$, $q$A publication or public figure maintains a presence on Mastodon to reach audiences seeking non-algorithmic, decentralized platforms.$q$, $q$Media organizations and public figures$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Public instance membership$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Join an existing Mastodon server","Post, follow, and interact across the Fediverse"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$Self-hosted instance$q$, $q$Free software (hosting costs apply)$q$, $q$n/a$q$, NULL, $q$["Full control over moderation and rules","Custom branding and domain","Requires own server infrastructure"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mastodon is free, open-source software for running decentralized social networks, created by developer Eugen Rochko and publicly released in October 2016. Rather than a single company operating one platform, Mastodon lets anyone run their own server, or instance, with its own community rules, while still interoperating with other instances through the ActivityPub protocol.$q$, $q$This federated structure, often called the Fediverse, means Mastodon functions more like email than a traditional social network: users on different servers can follow and interact with each other, and no single entity controls the entire network.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mastodon offers familiar social networking features, including posts (called toots or statuses), replies, boosts (similar to reposts), favorites, and direct messages, along with chronological, non-algorithmic timelines by default and granular content warnings.$q$, $q$Because each instance sets its own moderation policy, users can choose communities aligned with their interests or values, while cross-instance federation via ActivityPub still allows a global, interconnected timeline across the wider Fediverse, including compatible apps like Pixelfed and PeerTube.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mastodon the software is free and open source, and joining most public instances, including the flagship mastodon.social, costs nothing. There are no subscription fees for using the core social network.$q$, $q$Running your own instance is free of software licensing costs, but administrators must cover their own hosting, storage, and moderation costs, which scale with the size of the community they host.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9fecdcd9-2620-4cdf-982f-3615b76750b1', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
